#!/usr/bin/env python3
"""Auto-generated eval script for the Software Factory.

This script was generated by `factory discover`. It runs each eval dimension
as a subprocess and outputs JSON to stdout.

Output format:
    {"results": [{"name": str, "score": float, "weight": float, "passed": bool, "details": str}, ...]}

You can edit this file to add custom evals or adjust weights.
Once edited, it becomes a Tier 1 (explicit) eval — the factory will use it as-is.
"""

import json
import subprocess
import sys

def eval_lint() -> dict:
    """Run linter: npm run lint"""
    try:
        result = subprocess.run(
            ['npm', 'run', 'lint'],
            capture_output=True,
            text=True,
            timeout=120,
        )
        passed = result.returncode == 0
        if passed:
            score = 1.0
        else:
            # Partial score: count output lines as a rough error metric
            error_lines = [ln for ln in (result.stdout + result.stderr).splitlines() if ln.strip()]
            if not error_lines:
                score = 0.0
            else:
                score = max(0.0, 1.0 - len(error_lines) * 0.05)
        return {
            "name": 'lint',
            "score": score,
            "weight": 0.6666666666666666,
            "passed": passed,
            "details": (result.stdout or result.stderr).strip()[-500:],
        }
    except subprocess.TimeoutExpired:
        return {
            "name": 'lint',
            "score": 0.0,
            "weight": 0.6666666666666666,
            "passed": False,
            "details": "Timed out after 120s",
        }

def eval_type_check() -> dict:
    """Run type checker: npx tsc --noEmit"""
    try:
        result = subprocess.run(
            ['npx', 'tsc', '--noEmit'],
            capture_output=True,
            text=True,
            timeout=120,
        )
        passed = result.returncode == 0
        if passed:
            score = 1.0
        else:
            # Partial score: count output lines as a rough error metric
            error_lines = [ln for ln in (result.stdout + result.stderr).splitlines() if ln.strip()]
            if not error_lines:
                score = 0.0
            else:
                score = max(0.0, 1.0 - len(error_lines) * 0.05)
        return {
            "name": 'type_check',
            "score": score,
            "weight": 0.19999999999999998,
            "passed": passed,
            "details": (result.stdout or result.stderr).strip()[-500:],
        }
    except subprocess.TimeoutExpired:
        return {
            "name": 'type_check',
            "score": 0.0,
            "weight": 0.19999999999999998,
            "passed": False,
            "details": "Timed out after 120s",
        }

def eval_observability() -> dict:
    """Analyze observability coverage in TypeScript/TSX: console logging, structured logging, error handling."""
    import re
    from pathlib import Path

    skip = {
        "node_modules", ".git", ".factory", "eval", "dist", "build", ".next",
    }
    log_pats = [
        r"\bconsole\.(log|warn|error|info|debug)\(",
    ]
    struct_pats = [r"\bpino\b", r"\bwinston\b", r"\bstructuredLog\b"]
    error_handling_pats = [
        r"\btry\s*\{",
        r"\bcatch\s*\(",
    ]
    fn_pat = re.compile(
        r"(?:export\s+)?(?:async\s+)?function\s+\w+|"
        r"(?:const|let)\s+\w+\s*=\s*(?:async\s+)?\(?[^)]*\)?\s*=>|"
        r"(?:export\s+default\s+)?(?:async\s+)?function\b"
    )

    exts = {".ts", ".tsx"}
    sources = [
        f for f in Path("src").rglob("*")
        if f.suffix in exts and not any(p in f.parts for p in skip)
    ]
    total_fn = logged_fn = total_log = total_error_handling = 0
    has_struct = False

    for src in sources:
        try:
            code = src.read_text(errors="replace")
        except OSError:
            continue
        fns = fn_pat.findall(code)
        total_fn += len(fns)
        for pat in log_pats:
            matches = re.findall(pat, code)
            total_log += len(matches)
            if matches:
                logged_fn += min(len(matches), len(fns))
        for pat in struct_pats:
            if re.search(pat, code):
                has_struct = True
        for pat in error_handling_pats:
            total_error_handling += len(re.findall(pat, code))

    if total_fn == 0:
        return {"name": "observability", "score": 0.0, "weight": 0.13333333333333333,
                "passed": True, "details": "No functions found to analyze"}

    cov = min(1.0, logged_fn / total_fn)
    density = min(1.0, total_log / max(total_fn, 1))
    err_cov = min(1.0, total_error_handling / max(total_fn * 0.3, 1))
    score = 0.35 * cov + 0.25 * float(has_struct) + 0.25 * err_cov + 0.15 * density

    details = (f"log_coverage={cov:.0%} ({logged_fn}/{total_fn} fns), "
               f"structured={'yes' if has_struct else 'no'}, "
               f"error_handling={total_error_handling} blocks, "
               f"log_density={density:.0%}")

    return {"name": "observability", "score": round(score, 3), "weight": 0.13333333333333333,
            "passed": score >= 0.2, "details": details}

# Register all eval functions here.
EVALS = [eval_lint, eval_type_check, eval_observability]


def main() -> None:
    results = [fn() for fn in EVALS]
    output = {"results": results}
    json.dump(output, sys.stdout, indent=2)
    print()  # trailing newline


if __name__ == "__main__":
    main()
